/**
 * Checks if a CallExpression is calling a specific global identifier.
 *
 * This is useful for rules that need to detect global function calls like fetch(), alert(), etc.
 *
 * For example:
 * fetch('https://api.example.com') would return true when checking for 'fetch'
 * myObj.fetch() would return false when checking for 'fetch'
 */
export const isGlobalIdentifierCall = (node, identifierName) => {
    return (node.callee.type === 'Identifier' && node.callee.name === identifierName);
};
/**
 * Checks if a CallExpression or MemberExpression is accessing a property on window, globalThis, or self.
 *
 * This is useful for rules that need to detect browser global access patterns.
 *
 * Handles both:
 * - Dot notation: window.fetch, globalThis.fetch, or self.fetch
 * - Bracket notation: window['fetch'], globalThis['fetch'], or self['fetch']
 *
 * For example:
 * window.fetch('url') would return true when checking for 'fetch'
 * globalThis.fetch('url') would return true when checking for 'fetch'
 * self.fetch('url') would return true when checking for 'fetch'
 * window['fetch']('url') would return true when checking for 'fetch'
 * document.fetch('url') would return false when checking for 'fetch'
 */
export const isWindowSelfOrGlobalThisPropertyAccess = (node, propertyName) => {
    // Extract the MemberExpression from either a CallExpression or use it directly
    const memberExpression = node.type === 'CallExpression' ? node.callee : node;
    // Early exit: not a member expression
    if (memberExpression.type !== 'MemberExpression') {
        return false;
    }
    const { object, property, computed } = memberExpression;
    // Early exit: object is not window, globalThis, or self
    if (object.type !== 'Identifier' ||
        !['window', 'globalThis', 'self'].includes(object.name)) {
        return false;
    }
    // Check property name for both dot and bracket notation
    if (!computed && property.type === 'Identifier') {
        // Dot notation: window.fetch
        return property.name === propertyName;
    }
    if (computed && property.type === 'Literal') {
        // Bracket notation: window['fetch']
        return property.value === propertyName;
    }
    return false;
};
/**
 * Extracts the property name from a MemberExpression node.
 *
 * Handles both:
 * - Dot notation: object.propertyName (Identifier)
 * - Bracket notation: object['propertyName'] (Literal)
 *
 * For example:
 * - window.fetch → returns 'fetch'
 * - window['fetch'] → returns 'fetch'
 * - object.method → returns 'method'
 * - object[123] → returns '' (non-string literal)
 */
export const getMemberExpressionPropertyName = (memberExpression) => {
    const { property, computed } = memberExpression;
    // Dot notation: object.property
    if (!computed && property.type === 'Identifier') {
        return property.name;
    }
    // Bracket notation with string literal: object['property']
    if (computed &&
        property.type === 'Literal' &&
        typeof property.value === 'string') {
        return property.value;
    }
    return undefined;
};
